let a = [3, 7, 1];
let b = [7, 1, 3];

// Direct comparison
console.log('Direct ===:', a === b);

// Sort and compare as strings
let sortedA = a.slice().sort();
let sortedB = b.slice().sort();
console.log('Sorted toString match:', sortedA.toString() === sortedB.toString());

// Now try with different contents
let c = [3, 7, 2];
let sortedC = c.slice().sort();
console.log('Different contents match:', sortedA.toString() === sortedC.toString());
